{"code": "import json
import os

# Load the review data from the file path returned by query_db
reviews_file_path = locals().get('var_functions.query_db:14')
if isinstance(reviews_file_path, str) and os.path.exists(reviews_file_path):
    with open(reviews_file_path, 'r') as f:
        reviews_2020 = json.load(f)
else:
    reviews_2020 = reviews_file_path if reviews_file_path else []

# Load children's book data directly  
children_books = locals().get('var_functions.query_db:12', [])

# Convert rating strings to floats
for review in reviews_2020:
    if 'rating' in review:
        review['rating'] = float(review['rating'])

# Create mapping from purchase_id to average rating
from collections import defaultdict
purchase_ratings = defaultdict(list)
for review in reviews_2020:
    purchase_id = review.get('purchase_id')
    if purchase_id and review.get('rating') is not None:
        purchase_ratings[purchase_id].append(review['rating'])

purchase_avg_ratings = {
    pid: sum(ratings)/len(ratings) 
    for pid, ratings in purchase_ratings.items()
}

# Filter for purchase_ids with average rating >= 4.5
high_rated_purchase_ids = [
    pid for pid, avg_rating in purchase_avg_ratings.items() 
    if avg_rating >= 4.5
]

print('__RESULT__:')
print(json.dumps({
    'total_reviews_2020': len(reviews_2020),
    'children_books_found': len(children_books),
    'purchase_ids_with_ratings': len(purchase_avg_ratings),
    'high_rated_purchase_ids_count': len(high_rated_purchase_ids),
    'avg_ratings_sample': {k: round(v, 2) for k, v in list(purchase_avg_ratings.items())[:5]}
}))"}

